DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (`id` integer primary key AUTO_INCREMENT not null, `uuid` varchar not null, `connection` varchar not null, `queue` varchar not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP);

DROP TABLE IF EXISTS `faqs`;
CREATE TABLE `faqs` (`id` integer primary key AUTO_INCREMENT not null, `question` varchar not null, `answer` text not null, `category` varchar, `sort_order` integer not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

DROP TABLE IF EXISTS `galleries`;
CREATE TABLE `galleries` (`id` integer primary key AUTO_INCREMENT not null, `title` varchar not null, `description` text, `image` varchar not null, `category` varchar, `sort_order` integer not null default ('0'), `is_active` tinyint(1) not null default ('1'), `created_at` datetime, `updated_at` datetime, `category_id` integer, `slug` varchar, `alt_text` varchar, `meta_title` varchar, `meta_description` text, `tags` text, `service_id` integer, `project_id` integer, `views` integer not null default '0', `meta_keywords` text, `canonical_url` varchar, `is_indexed` tinyint(1) not null default '1', foreign key(`category_id`) references categories(`id`) on delete set null on update no action, foreign key(`service_id`) references `services`(`id`) on delete set null, foreign key(`project_id`) references `projects`(`id`) on delete set null);

