DROP TABLE IF EXISTS `materials`;
CREATE TABLE `materials` (`id` integer primary key AUTO_INCREMENT not null, `material_category_id` integer not null, `name` varchar not null, `slug` varchar not null, `description` text, `image` varchar, `images` text, `price` numeric, `specifications` text, `tags` varchar, `is_active` tinyint(1) not null default ('1'), `meta_title` varchar, `meta_description` text, `meta_keywords` varchar, `created_at` datetime, `updated_at` datetime, `views` integer not null default '0', `canonical_url` varchar, `is_indexed` tinyint(1) not null default '1', foreign key(`material_category_id`) references `categories`(`id`) on delete cascade);

INSERT INTO `materials` (`id`, `material_category_id`, `name`, `slug`, `description`, `image`, `images`, `price`, `specifications`, `tags`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('1', '1', 'بديل الخشب الجديد | أحدث حلول الديكورات الداخلية في مكة وجدة', 'wood', 'يعد بديل الخشب الجديد من أحدث مواد التشطيب والديكور التي تجمع بين المظهر الطبيعي للخشب والمتانة العالية وسهولة التركيب. يستخدم في تصميم الجدران والأسقف وديكورات التلفزيون والمداخل والمكاتب والمجالس، ويتميز بمقاومته للرطوبة والحشرات وسهولة تنظيفه مقارنة بالخشب الطبيعي. يتوفر بتصاميم وألوان متنوعة تناسب الديكورات الحديثة والكلاسيكية، مما يجعله خيارًا مثاليًا للمنازل والفلل والشركات في مكة وجدة.', 'materials/6a3f197f3f2a3.webp', '["materials\/6a3f1980019f6.webp"]', NULL, 'مظهر طبيعي يحاكي الخشب الفاخر.
مقاوم للرطوبة والعوامل الجوية الداخلية.
مقاوم للحشرات والتآكل.
خفيف الوزن وسهل التركيب.
سهل التنظيف والصيانة.
يتوفر بألوان ونقوش متعددة.
مناسب للجدران والأسقف والأعمدة.
يستخدم في المنازل والفلل والمكاتب والمعارض.
إمكانية دمجه مع بديل الرخام والإضاءة المخفية.
عمر افتراضي طويل مع جودة عالية.', '["\u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628\u060c \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628 \u0627\u0644\u062c\u062f\u064a\u062f\u060c \u0623\u0644\u0648\u0627\u062d \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628\u060c \u062f\u064a\u0643\u0648\u0631\u0627\u062a \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628\u060c \u062a\u0631\u0643\u064a\u0628 \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628\u060c \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628 \u0645\u0643\u0629\u060c \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628 \u062c\u062f\u0629\u060c \u062f\u064a\u0643\u0648\u0631 \u062c\u062f\u0631\u0627\u0646\u060c \u062f\u064a\u0643\u0648\u0631 \u062f\u0627\u062e\u0644\u064a\u060c \u062a\u0635\u0645\u064a\u0645 \u062f\u0627\u062e\u0644\u064a"]', '1', 'بديل الخشب الجديد في مكة وجدة | تركيب وتصميم ديكورات بديل الخشب بأفضل الأسعار', 'نوفر خدمات تصميم وتركيب بديل الخشب الجديد في مكة وجدة بأحدث التصاميم العصرية وجودة عالية. مناسب للجدران والأسقف وديكورات التلفزيون والمجالس والمكاتب مع تنفيذ احترافي وأسعار تنافسية.', 'بديل الخشب، بديل الخشب الجديد، تركيب بديل الخشب، بديل الخشب مكة، بديل الخشب جدة، ديكورات بديل الخشب، ألواح بديل الخشب، بديل الخشب للجدران، بديل الخشب للأسقف، بديل الخشب للشاشات، ديكور بديل الخشب، تصميم داخلي مكة، تصميم داخلي جدة، تشطيبات داخلية، ديكورات حديثة، ديكور مجالس، ديكور فلل، بديل الخشب مقاوم للرطوبة، أفضل بديل خشب، أسعار بديل الخشب', '2026-06-27 00:29:52', '2026-06-27 01:23:51', '5', NULL, '1');

