DROP TABLE IF EXISTS `projects`;
CREATE TABLE `projects` (`id` integer primary key AUTO_INCREMENT not null, `title` varchar not null, `slug` varchar not null, `description` text, `images` text, `videos` text, `service_id` integer, `is_active` tinyint(1) not null default ('1'), `meta_title` varchar, `meta_description` text, `meta_keywords` varchar, `created_at` datetime, `updated_at` datetime, `category_id` integer, `image` varchar, `views` integer not null default '0', `canonical_url` varchar, `is_indexed` tinyint(1) not null default '1', `sort_order` integer not null default '0', `tags` text, foreign key(`category_id`) references categories(`id`) on delete cascade on update no action, foreign key(`service_id`) references services(`id`) on delete cascade on update no action);

INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('1', 'جدار تلفاز عصري مع إضاءة مخفية', 'modern-tv-wall-led-lighting', 'تصميم جدار تلفاز عصري يجمع بين الجبس بورد والإضاءة المخفية LED وبديل الخشب الفاخر. تم تنفيذ هذا التصميم في فيلا سكنية لإضفاء لمسة عصرية دافئة على غرفة المعيشة.', '["projects\/project-tv-1.jpg","projects\/gallery\/6a39aea8a8de5.webp","projects\/gallery\/6a39aea9668cf.webp","projects\/gallery\/6a39aeaa11e3a.webp","projects\/gallery\/6a39aeaab71b9.webp","projects\/gallery\/6a39aeab5fb7c.webp","projects\/gallery\/6a39aeac0e6ce.webp","projects\/gallery\/6a39aeacadc2a.webp","projects\/gallery\/6a39aead5000e.webp","projects\/gallery\/6a39aeadeed6a.webp","projects\/gallery\/6a39aeaeacf85.webp","projects\/gallery\/6a39aeaf58a67.webp","projects\/gallery\/6a39aeafefecc.webp","projects\/gallery\/6a39aeb0d6739.webp","projects\/gallery\/6a39aeb192294.webp","projects\/gallery\/6a39aeb248b01.webp","projects\/gallery\/6a39aeb2b7754.webp","projects\/gallery\/6a39aeb36040f.webp","projects\/gallery\/6a39aeb41feaa.webp","projects\/gallery\/6a39aeb4b7d27.webp","projects\/gallery\/6a39aeb551a3a.webp"]', NULL, '13', '0', 'دار تلفاز عصري مع إضاءة مخفية في السعودية | تصميم ديكور تلفزيون مودرن وفاخر', 'نقدم تصميم وتنفيذ جدار تلفاز عصري مع إضاءة مخفية في السعودية بتشطيبات حديثة تشمل بديل الرخام والخشب والجبس بورد، لإضافة لمسة فخامة وإضاءة LED تناسب الصالات والمجالس.', 'جدار تلفاز عصري، ديكور تلفزيون مودرن، جدار TV، ديكور شاشة تلفاز، إضاءة مخفية للتلفزيون، جدار تلفاز LED، بديل الرخام للتلفزيون، ديكور خشب للتلفزيون، تصميم جدار تلفزيون، ديكور صالة تلفاز، جدار تلفزيون فاخر، ديكورات شاشات حديثة، جبس بورد للتلفزيون، ديكور تلفاز مودرن، تصميم شاشة تلفاز سعودي', '2026-06-19 14:47:57', '2026-06-22 23:03:03', NULL, NULL, '2', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('2', 'ديكور شاشة تلفاز مع بديل الرخام', 'tv-screen-marble-replacement', 'ديكور شاشة تلفاز فاخر باستخدام بديل الرخام الطبيعي مع أرفف عرض مضيئة. تم التصميم ليكون محورياً في المجلس الرئيسي مع لمسات من الذهبي لإبراز الفخامة.', '["projects\/project-tv-2.jpg","projects\/gallery\/6a39af19c5045.webp","projects\/gallery\/6a39af1a73c94.webp","projects\/gallery\/6a39af1b247dc.webp","projects\/gallery\/6a39af1bd22c9.webp","projects\/gallery\/6a39af1c7a5d6.webp","projects\/gallery\/6a39af1d2c52f.webp","projects\/gallery\/6a39af1dbfd9c.webp","projects\/gallery\/6a39af1e73034.webp","projects\/gallery\/6a39af1f1f3e8.webp","projects\/gallery\/6a39af1fce601.webp","projects\/gallery\/6a39af207dc8b.webp","projects\/gallery\/6a39af2121265.webp","projects\/gallery\/6a39af21e0c4f.webp","projects\/gallery\/6a39af2297d9d.webp","projects\/gallery\/6a39af23556fa.webp","projects\/gallery\/6a39af23c8551.webp","projects\/gallery\/6a39af246f98d.webp","projects\/gallery\/6a39af25216b8.webp","projects\/gallery\/6a39af25c8fdc.webp","projects\/gallery\/6a39bed246d66.webp","projects\/gallery\/6a39bed2f32f0.webp","projects\/gallery\/6a39bed3b71da.webp","projects\/gallery\/6a39bed460de2.webp","projects\/gallery\/6a39bed518bdb.webp","projects\/gallery\/6a39bed5d5365.webp","projects\/gallery\/6a39bed689664.webp","projects\/gallery\/6a39bed7308dd.webp","projects\/gallery\/6a39bed7dd483.webp","projects\/gallery\/6a39bed898c86.webp","projects\/gallery\/6a39bed953a4d.webp","projects\/gallery\/6a39beda0a7cf.webp","projects\/gallery\/6a39bedab5b5f.webp","projects\/gallery\/6a39bedb76eda.webp","projects\/gallery\/6a39bedc396e1.webp","projects\/gallery\/6a39bedce2c2c.webp","projects\/gallery\/6a39bedd9f4a6.webp","projects\/gallery\/6a39bede45bf8.webp","projects\/gallery\/6a39bedee440c.webp","projects\/gallery\/6a39bedfa862d.webp"]', NULL, '13', '1', 'ديكور شاشة تلفاز مع بديل الرخام في السعودية | تصميم جدار TV فاخر ومودرن', 'نقدم تصميم وتنفيذ ديكور شاشة تلفاز مع بديل الرخام في السعودية بأفكار عصرية وفاخرة، يشمل جدران تلفزيون أنيقة مع إضاءة مخفية وتشطيبات عالية الجودة تناسب المجالس والصالات الحديثة.', 'ديكور شاشة تلفاز، بديل الرخام للتلفزيون، جدار تلفاز بديل الرخام، ديكور TV مودرن، جدار تلفزيون فاخر، ديكور شاشة تلفزيون حديث، تصميم جدار تلفاز، ديكور صالة تلفاز، بديل الرخام للجدران، ديكور تلفاز فاخر، شاشات تلفاز ديكورية، جدار TV مودرن، تصميم شاشة تلفاز، ديكور جدران التلفاز، أفكار ديكور التلفزيون', '2026-06-19 14:47:57', '2026-06-26 23:10:01', NULL, 'projects/6a39af1916320.webp', '2', NULL, '1', '2', '["\u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u062a\u0644\u0641\u0632\u064a\u0648\u0646\u060c \u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u0645\u0643\u0629\u060c \u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u062c\u062f\u0629\u060c \u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628\u060c \u0628\u062f\u064a\u0644 \u0627\u0644\u0631\u062e\u0627\u0645\u060c \u062f\u064a\u0643\u0648\u0631\u0627\u062a \u0645\u0648\u062f\u0631\u0646\u060c \u062a\u0635\u0645\u064a\u0645 \u062f\u0627\u062e\u0644\u064a\u060c \u062f\u064a\u0643\u0648\u0631\u0627\u062a \u0635\u0627\u0644\u0627\u062a\u060c \u062f\u064a\u0643\u0648\u0631 \u0645\u062c\u0627\u0644\u0633\u060c \u0625\u0636\u0627\u0621\u0629 LED"]');
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('3', 'جدار تلفاز كلاسيكي مع خشب طبيعي', 'classic-tv-wall-natural-wood', 'جدار تلفاز بتصميم كلاسيكي أنيق باستخدام الخشب الطبيعي والجبس بورد. يتضمن التصميم أرفف جانبية للأكسسوارات والديكورات مع إضاءة مخفية تبرز جمال الخشب.', '["projects\/project-tv-3.jpg","projects\/gallery\/6a39afb81c603.webp","projects\/gallery\/6a39afb8deb70.webp","projects\/gallery\/6a39afb98bb1c.webp","projects\/gallery\/6a39afba3336a.webp","projects\/gallery\/6a39afbae401b.webp","projects\/gallery\/6a39afbb99684.webp","projects\/gallery\/6a39afbc3951a.webp","projects\/gallery\/6a39afbce2d78.webp","projects\/gallery\/6a39afbd8b4f8.webp","projects\/gallery\/6a39afbe3e0ce.webp","projects\/gallery\/6a39afbedb489.webp","projects\/gallery\/6a39afbf9a5ac.webp","projects\/gallery\/6a39afc0463ac.webp","projects\/gallery\/6a39afc0ee1f7.webp","projects\/gallery\/6a39afc18bbc9.webp","projects\/gallery\/6a39afc23f7a9.webp","projects\/gallery\/6a39afc2ef079.webp","projects\/gallery\/6a39afc394006.webp","projects\/gallery\/6a39afc434e9a.webp"]', NULL, '13', '1', 'جدار تلفاز كلاسيكي مع خشب طبيعي في السعودية | تصميم ديكور TV فاخر كلاسيك', 'نقدم تصميم وتنفيذ جدار تلفاز كلاسيكي مع خشب طبيعي في السعودية بأسلوب فاخر يجمع بين الأصالة والفخامة، مع تشطيبات عالية الجودة تناسب المجالس والصالات الكلاسيكية.', 'جدار تلفاز كلاسيكي، ديكور تلفاز خشب طبيعي، جدار TV كلاسيك، ديكور شاشة تلفاز كلاسيكي، خشب طبيعي للتلفزيون، جدار تلفزيون خشبي، تصميم تلفاز كلاسيكي، ديكور صالة كلاسيك، جدار TV فاخر، ديكور تلفاز خشبي مودرن كلاسيك، ديكورات خشب للجدران، تصميم جدار تلفاز فخم، ديكور تلفزيون كلاسيكي، جدار تلفاز فاخر خشب، أفكار ديكور تلفاز كلاسيك', '2026-06-19 14:47:57', '2026-06-22 21:57:24', NULL, 'projects/6a39afb76a1c7.webp', '0', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('4', 'جدار مرايا فاخر مع إضاءة LED', 'luxury-mirror-wall-led-lighting', 'تصميم جدار مرايا فاخر يجمع بين المرايا المزخرفة والإضاءة المخفية LED. تم تنفيذ هذا التصميم في صالة استقبال لإضفاء لمسة من الاتساع والفخامة مع انعكاسات ضوئية مبهرة.', '["projects\/mirror-project-1.jpg","projects\/gallery\/6a39ac98ee434.webp","projects\/gallery\/6a39ac999a3b6.webp","projects\/gallery\/6a39ac9a4be9b.webp","projects\/gallery\/6a39ac9b08f5f.webp","projects\/gallery\/6a39ac9bbb302.webp","projects\/gallery\/6a39ac9c6fb2b.webp","projects\/gallery\/6a39ac9d3a5d0.webp","projects\/gallery\/6a39ac9ddfd06.webp","projects\/gallery\/6a39ac9e9e993.webp","projects\/gallery\/6a39ac9f67a61.webp","projects\/gallery\/6a39aca0331d1.webp","projects\/gallery\/6a39aca104003.webp","projects\/gallery\/6a39aca1c37c7.webp","projects\/gallery\/6a39aca27254b.webp","projects\/gallery\/6a39aca32bec8.webp","projects\/gallery\/6a39aca3e6362.webp","projects\/gallery\/6a39aca4a01cb.webp","projects\/gallery\/6a39aca559926.webp","projects\/gallery\/6a39aca5eeb49.webp","projects\/gallery\/6a39aca6bbb62.webp"]', NULL, '6', '1', 'مشاريع جدار مرايا فاخر مع إضاءة LED في السعودية | تصميم مرايا ديكورية مودرن', 'نقدم تنفيذ مشاريع جدار مرايا فاخر مع إضاءة LED في السعودية بتصاميم عصرية ومودرن تناسب المجالس والصالات وغرف النوم، مع تشطيبات عالية الجودة ولمسة فخامة وإضاءة ديكورية مميزة.', 'جدار مرايا، مرايا LED، جدار مرايا فاخر، مرايا ديكورية، مرايا إضاءة مخفية، ديكور مرايا مودرن، مرايا جدارية، تصميم جدار مرايا، إضاءة LED ديكورية، مرايا صالات، مرايا مجالس، ديكور إضاءة حديث، مرايا فخمة، تصميم مرايا داخلية، جدران مرايا فاخرة', '2026-06-19 15:05:46', '2026-06-26 22:01:43', NULL, NULL, '3', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('5', 'ديكور مرايا مدخل مع أرفف مضيئة', 'mirror-entrance-decorative-shelves', 'ديكور مرايا أنيق للمدخل الرئيسي مع أرفف عرض مضيئة وأطارات ذهبية. يمنح المدخل إحساساً بالرحابة والترحيب مع لمسة عصرية.', '["projects\/mirror-project-2.jpg","projects\/gallery\/6a39add3b3783.webp","projects\/gallery\/6a39add4486e4.webp","projects\/gallery\/6a39add4d432a.webp","projects\/gallery\/6a39add587ab5.webp","projects\/gallery\/6a39add6540a9.webp","projects\/gallery\/6a39add706555.webp","projects\/gallery\/6a39add7b5d64.webp","projects\/gallery\/6a39add86e323.webp","projects\/gallery\/6a39add938429.webp","projects\/gallery\/6a39add9e07be.webp"]', NULL, '6', '1', 'ديكور مرايا مدخل مع أرفف مضيئة في السعودية | تصميم مداخل مودرن وفاخرة', 'نقدم تصميم وتنفيذ ديكور مرايا مدخل مع أرفف مضيئة في السعودية بأفكار عصرية وفاخرة، لإبراز مدخل المنزل بشكل أنيق مع إضاءة LED وإكسسوارات ديكورية تضيف لمسة استقبال راقية.', 'ديكور مرايا مدخل، مرايا مداخل، أرفف مضيئة، ديكور مدخل منزل، مرايا LED مدخل، تصميم مدخل مودرن، ديكور مداخل فاخرة، أرفف ديكورية مضيئة، مرايا جدارية مدخل، ديكور استقبال منزل، إضاءة مدخل منزل، ديكورات مداخل حديثة، تصميم مداخل فلل، مرايا ديكور مدخل، أفكار مداخل مودرن', '2026-06-19 15:05:46', '2026-06-22 21:49:14', NULL, 'projects/6a39add30e0bf.webp', '0', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('6', 'جدار مرايا غرفة معيشة مع ديكور خشبي', 'living-room-mirror-wall-wood-decor', 'جدار مرايا مميز لغرفة المعيشة يجمع بين قطع المرايا المتنوعة والإطارات الخشبية الفاخرة والإضاءة الدافئة المخفية.', '["projects\/mirror-project-3.jpg"]', NULL, '6', '1', NULL, NULL, NULL, '2026-06-19 15:05:46', '2026-06-20 20:47:08', NULL, NULL, '2', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('7', 'ديكورات غرف النوم الحديثة', 'bed room', 'مشروع ديكورات غرف النوم الحديثة يركز على تصميم مساحات نوم عصرية تجمع بين الراحة والفخامة، باستخدام ألوان هادئة، إضاءة ذكية، وأساليب تصميم داخلي مبتكرة تناسب مختلف المساحات والأذواق.', '["projects\/gallery\/6a36e9816e9e4.webp","projects\/gallery\/6a36e9822d544.webp","projects\/gallery\/6a36e982c1e3c.webp","projects\/gallery\/6a36e98385d90.webp","projects\/gallery\/6a36e9845318e.webp","projects\/gallery\/6a36e985154d4.webp","projects\/gallery\/6a36e985dbd69.webp","projects\/gallery\/6a36e98699f2a.webp","projects\/gallery\/6a36e9875b626.webp","projects\/gallery\/6a36e98807b3a.webp","projects\/gallery\/6a36e98899d83.webp","projects\/gallery\/6a36e989614ac.webp","projects\/gallery\/6a36e98a133d3.webp","projects\/gallery\/6a36e98ac60f4.webp","projects\/gallery\/6a36e98b8b884.webp","projects\/gallery\/6a36e98c40e3b.webp","projects\/gallery\/6a36e98d1387c.webp","projects\/gallery\/6a36e98dd38f0.webp","projects\/gallery\/6a36e98ec1a4e.webp"]', NULL, NULL, '1', 'ديكورات غرف النوم الحديثة | تصاميم مودرن أنيقة وعصرية', 'مشروع ديكورات غرف النوم الحديثة يقدم أفكار وتصاميم مودرن تجمع بين الراحة والفخامة، مع حلول ديكور عصرية تناسب جميع المساحات والأذواق.', 'ديكورات غرف النوم، ديكورات غرف نوم حديثة، غرف نوم مودرن، تصميم غرف نوم عصرية، ديكورات غرف نوم فاخرة، ديكور غرفة النوم، غرف نوم حديثة 2026، تصميم داخلي لغرف النوم، أفكار ديكورات غرف النوم، غرف نوم كلاسيك، غرف نوم معاصرة، ديكورات غرف نوم صغيرة، غرف نوم رئيسية، غرف نوم للعرسان، أثاث غرف النوم، ديكورات جدران غرف النوم، ديكورات أسقف غرف النوم، جبس غرف النوم، إضاءة غرف النوم، ألوان غرف النوم الحديثة، غرف نوم فاخرة، تصميم غرفة نوم مودرن، غرف نوم بسيطة وأنيقة، ديكورات غرف نوم سعودية، أفضل تصاميم غرف النوم، تنسيق غرف النوم، مفروشات غرف النوم، غرف نوم راقية، ديكورات داخلية لغرف النوم، أفكار غرف نوم عصرية.', '2026-06-20 19:27:11', '2026-06-27 01:23:55', NULL, 'projects/6a36e980a24fa.webp', '11', NULL, '1', '0', NULL);
INSERT INTO `projects` (`id`, `title`, `slug`, `description`, `images`, `videos`, `service_id`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `category_id`, `image`, `views`, `canonical_url`, `is_indexed`, `sort_order`, `tags`) VALUES ('8', 'ديكورات شاشات تلفزيون حديثة في مكة وجدة', 'tv-wall-design-makkah-jeddah', 'يقدم هذا المشروع تصميمًا وتنفيذًا احترافيًا لديكورات شاشات التلفزيون في مكة وجدة بأسلوب يجمع بين الفخامة والعملية، حيث تم تنفيذ مشاريع جدار التلفزيون باستخدام بديل الخشب وبديل الرخام وبديل الحجر والشيبورد  عالي الجودة مع لمسات من بديل الرخام وإضاءة LED مخفية تمنح المكان مظهرًا عصريًا راقيًا. تم توزيع العناصر بعناية لإبراز الشاشاشات وتحويلها إلى نقطة جذب رئيسية داخل الصالة أو المجلس.

اعتمد التصميم على خامات مقاومة للرطوبة وسهلة التنظيف، مع تشطيبات دقيقة تضيف لمسة من الأناقة وتضمن المحافظة على جودة الديكور لسنوات طويلة. كما تم اختيار الألوان بما يتناسب مع مختلف أنماط الأثاث الحديث والكلاسيكي، مما يمنح المساحة انسجامًا بصريًا مميزًا.

يعد هذا النوع من ديكورات الشاشات من أكثر التصاميم طلبًا في مكة وجدة، خاصة في الفلل والشقق الحديثة، حيث يجمع بين الجمال والتنظيم من خلال دمج الأرفف الديكورية، والإضاءة المخفية، والخزائن السفلية التي توفر مساحة عملية لتخزين الأجهزة والإكسسوارات.

يحرص فريق ديكورات المصمم الذكي على تنفيذ كل مشروع وفق مقاسات المكان واحتياجات العميل، مع تقديم حلول تصميم داخلية تناسب المساحات الكبيرة والصغيرة، واستخدام أحدث خامات الديكور التي تمنح الجدار مظهرًا فاخرًا يواكب أحدث اتجاهات التصميم الداخلي.

سواء كنت تبحث عن ديكور شاشة مودرن، أو جدار تلفزيون ببديل الخشب، أو تصميم فاخر ببديل الرخام والإضاءة المخفية، فإن هذه المشاريع تمثل نموذجًا يجمع بين الجودة العالية، ودقة التنفيذ، واللمسات الجمالية التي تضيف قيمة حقيقية لمنزلك أو مكتبك.

إذا كنت ترغب في تجديد صالة المعيشة أو المجلس أو غرفة الاستقبال، فإن تنفيذ ديكور شاشة تلفزيون احترافي يعد من أفضل الحلول لإبراز جمال المكان وزيادة فخامته، مع الاعتماد على مواد عالية الجودة وتشطيبات دقيقة تناسب مختلف الأذواق في مكة وجدة.', '["projects\/gallery\/6a3f04761d8e1.webp","projects\/gallery\/6a3f0476d7e35.webp","projects\/gallery\/6a3f04779715c.webp","projects\/gallery\/6a3f04784e650.webp","projects\/gallery\/6a3f0479097f8.webp","projects\/gallery\/6a3f0479ca0f3.webp","projects\/gallery\/6a3f047a817c9.webp","projects\/gallery\/6a3f047b482a5.webp","projects\/gallery\/6a3f047c09c62.webp","projects\/gallery\/6a3f047cd8875.webp","projects\/gallery\/6a3f047d857e8.webp","projects\/gallery\/6a3f047e3a70b.webp","projects\/gallery\/6a3f047eda9ce.webp","projects\/gallery\/6a3f047f84417.webp","projects\/gallery\/6a3f0480230fb.webp","projects\/gallery\/6a3f0480ce7e1.webp","projects\/gallery\/6a3f048179b69.webp","projects\/gallery\/6a3f04821bfba.webp","projects\/gallery\/6a3f0482c1165.webp"]', NULL, NULL, '1', 'ديكورات شاشات تلفزيون في مكة وجدة | تصميم وتنفيذ شاشات مودرن وفاخرة', 'تنفيذ أحدث ديكورات شاشات التلفزيون في مكة وجدة باستخدام بديل الخشب وبديل الرخام والإضاءة المخفية، مع تصاميم مودرن وتشطيبات احترافية تناسب الفلل والشقق والمجالس والصالات.', 'ديكورات شاشات تلفزيون، ديكور شاشة مكة، ديكور شاشة جدة، جدار شاشة مودرن، بديل الخشب للشاشات، بديل الرخام للشاشات، تصميم شاشات تلفزيون، ديكور تلفزيون حديث، ديكورات داخلية مكة، ديكورات داخلية جدة، تصميم صالات، تصميم مجالس، تنفيذ ديكورات، ديكور مودرن، شاشة تلفزيون فاخرة', '2026-06-26 22:51:56', '2026-06-26 23:16:43', NULL, 'projects/6a3f0473a0a69.webp', '2', NULL, '1', '1', '["\u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u062a\u0644\u0641\u0632\u064a\u0648\u0646","\u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u0645\u0643\u0629","\u062f\u064a\u0643\u0648\u0631 \u0634\u0627\u0634\u0629 \u062c\u062f\u0629","\u0628\u062f\u064a\u0644 \u0627\u0644\u062e\u0634\u0628","\u0628\u062f\u064a\u0644 \u0627\u0644\u0631\u062e\u0627\u0645","\u062f\u064a\u0643\u0648\u0631\u0627\u062a \u0645\u0648\u062f\u0631\u0646","\u062a\u0635\u0645\u064a\u0645 \u062f\u0627\u062e\u0644\u064a","\u062f\u064a\u0643\u0648\u0631\u0627\u062a \u0635\u0627\u0644\u0627\u062a","\u062f\u064a\u0643\u0648\u0631 \u0645\u062c\u0627\u0644\u0633","\u0625\u0636\u0627\u0621\u0629 LED"]');

DROP TABLE IF EXISTS `reviews`;
CREATE TABLE `reviews` (`id` integer primary key AUTO_INCREMENT not null, `name` varchar not null, `text` text not null, `stars` integer not null default '5', `image` varchar, `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `reply` text);

INSERT INTO `reviews` (`id`, `name`, `text`, `stars`, `image`, `is_active`, `created_at`, `updated_at`, `reply`) VALUES ('1', 'أحمد القحطاني', 'أشكر فريق المصمم الذكي على الاحترافية والذوق العالي في تنفيذ ديكور منزلي. النتيجة تجاوزت توقعاتي بكل معنى الكلمة.', '5', NULL, '1', '2026-06-19 02:47:14', '2026-06-19 02:47:14', NULL);
INSERT INTO `reviews` (`id`, `name`, `text`, `stars`, `image`, `is_active`, `created_at`, `updated_at`, `reply`) VALUES ('2', 'سارة العنزي', 'تعاملت معهم في تصميم مكتبي وكانت تجربة رائعة. التصاميم مبتكرة والتنفيذ دقيق وفي الوقت المحدد. أنصح بالتعامل معهم.', '5', NULL, '1', '2026-06-19 02:47:14', '2026-06-19 02:47:14', NULL);
INSERT INTO `reviews` (`id`, `name`, `text`, `stars`, `image`, `is_active`, `created_at`, `updated_at`, `reply`) VALUES ('3', 'محمد الدوسري', 'خدمة ممتازة وفريق محترف. ساعدوني في اختيار أفضل المواد والديكورات بأسعار مناسبة. شكراً لكم.', '4', NULL, '1', '2026-06-19 02:47:14', '2026-06-19 02:47:14', NULL);
INSERT INTO `reviews` (`id`, `name`, `text`, `stars`, `image`, `is_active`, `created_at`, `updated_at`, `reply`) VALUES ('4', 'نورة الشمري', 'صالة الاستقبال في منزلي أصبحت تحفة فنية بفضل المصمم الذكي. الاختيارات كانت ذكية والتنفيذ رائع.', '5', NULL, '1', '2026-06-19 02:47:14', '2026-06-19 02:47:14', NULL);
INSERT INTO `reviews` (`id`, `name`, `text`, `stars`, `image`, `is_active`, `created_at`, `updated_at`, `reply`) VALUES ('5', 'فهد المطيري', 'أفضل شركة ديكور تعاملت معها. الاهتمام بالتفاصيل والجودة العالية في العمل يميزهم عن غيرهم. تجربة تستحق التكرار.', '5', NULL, '1', '2026-06-19 02:47:14', '2026-06-19 02:47:14', NULL);

DROP TABLE IF EXISTS `service_material_category`;
CREATE TABLE `service_material_category` (`service_id` integer not null, `material_category_id` integer not null, `created_at` datetime, `updated_at` datetime, foreign key(`service_id`) references services(`id`) on delete cascade on update no action, foreign key(`material_category_id`) references `categories`(`id`) on delete cascade);

DROP TABLE IF EXISTS `service_project`;
CREATE TABLE `service_project` (`service_id` integer not null, `project_id` integer not null, `created_at` datetime, `updated_at` datetime, foreign key(`service_id`) references `services`(`id`) on delete cascade, foreign key(`project_id`) references `projects`(`id`) on delete cascade);

