DROP TABLE IF EXISTS `services`;
CREATE TABLE `services` (`id` integer primary key AUTO_INCREMENT not null, `name` varchar not null, `slug` varchar not null, `description` text not null, `icon` varchar, `image` varchar, `images` text, `videos` text, `sort_order` integer not null default '0', `is_active` tinyint(1) not null default '1', `meta_title` varchar, `meta_description` text, `meta_keywords` varchar, `created_at` datetime, `updated_at` datetime, `views` integer not null default '0', `canonical_url` varchar, `is_indexed` tinyint(1) not null default '1');

INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('2', 'الديكورات الخارجية', 'exterior-decorations', 'تصميم وتنفيذ ديكورات خارجية مميزة للواجهات والمداخل والحدائق، تجمع بين الجمال والوظائف العملية لتعطي انطباعاً فريداً لمبناك.', NULL, 'services/6a39a50b34b38.webp', '["services\/gallery\/6a39a50c10020.webp","services\/gallery\/6a39a50cc3a1c.webp","services\/gallery\/6a39a50da9b6c.webp","services\/gallery\/6a39a50e97f20.webp"]', NULL, '1', '1', 'خدمة الديكورات الخارجية للمنازل والفلل في السعودية مكة جدة | تصميم واجهات وجلسات خارجية', 'نقدم خدمة الديكورات الخارجية للمنازل والفلل في السعودية بأحدث التصاميم العصرية، تشمل الواجهات الخارجية، الجلسات الخارجية، الحدائق، والمداخل الفخمة بأعلى جودة وتشطيبات احترافية تناسب جميع الأذواق.', 'الديكورات الخارجية، تصميم واجهات منازل، ديكورات فلل خارجية، واجهات خارجية مودرن، جلسات خارجية، تصميم حدائق منزلية، ديكور خارجي فاخر، تشطيبات خارجية، واجهات حجر طبيعي، ديكور مداخل منازل، تصميم مساحات خارجية، ديكورات خارجية حديثة، تنسيق حدائق، واجهات فلل سعودية، تحسين واجهة المنزل', '2026-06-19 02:14:24', '2026-06-22 21:11:43', '3', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('3', 'ديكورات الجدران', 'wall-decorations', 'تشكيلة واسعة من حلول ديكورات الجدران تشمل ورق الجدران، الفوم، الاستيل، والدهانات الفنية لإضفاء لمسات جمالية مميزة على جدران منزلك.', NULL, 'services/6a39a5b7e5acc.webp', '["services\/gallery\/6a39a5b8a946a.webp","services\/gallery\/6a39a5b96c03e.webp","services\/gallery\/6a39a5ba297be.webp","services\/gallery\/6a39a5bad80eb.webp"]', NULL, '2', '1', 'خدمة ديكورات الجدران الحديثة في السعودية | بديل الرخام والخشب والحجر للجدران', 'نقدم خدمة ديكورات الجدران في السعودية بتصاميم عصرية وفاخرة تشمل بديل الرخام، بديل الخشب، الحجر الطبيعي، وجدران التلفزيون بأعلى جودة وتشطيبات احترافية تناسب جميع المساحات.', 'ديكورات الجدران، ديكور جدران مودرن، بديل الرخام للجدران، بديل الخشب للجدران، ديكورات جدران التلفزيون، جدران حجر طبيعي، تكسية الجدران، تصميم جدران داخلية، ديكور حائط حديث، أفكار ديكور الجدران، تشطيب الجدران، ديكورات حوائط فخمة، ديكور جدران ثلاثي الأبعاد، جدران ديكورية، تحسين ديكور الجدران', '2026-06-19 02:14:24', '2026-06-22 21:14:35', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('4', 'ديكورات الأسقف', 'ceiling-decorations', 'تصاميم أسقف جبسية مبتكرة ومعلقة مع أنظمة إضاءة مدمجة، تضفي عمقاً وجمالاً على المساحات الداخلية.', NULL, 'services/6a39a6562018c.webp', '["services\/gallery\/6a39a656c75dd.webp","services\/gallery\/6a39a65780b70.webp","services\/gallery\/6a39a65838810.webp"]', NULL, '3', '1', 'خدمة ديكورات الأسقف الجبسية الحديثة في السعودية | تصميم أسقف مودرن وفاخرة', 'نقدم خدمة ديكورات الأسقف في السعودية بتصاميم جبس بورد حديثة وفاخرة تشمل الأسقف المعلقة والإضاءة المخفية، لتناسب المجالس وغرف النوم والصالات بأعلى جودة وتشطيبات احترافية.', 'ديكورات الأسقف، أسقف جبس بورد، ديكور سقف مودرن، أسقف معلقة، إضاءة مخفية للأسقف، تصميم أسقف داخلية، ديكورات أسقف فخمة، جبس بورد حديث، أسقف غرف نوم، أسقف مجالس، ديكور سقف جبسي، تصميم سقف عصري، تشطيب الأسقف، ديكورات سقف للفلل، أسقف مودرن فاخرة', '2026-06-19 02:14:24', '2026-06-22 21:17:12', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('5', 'الأرضيات والباركيه', 'flooring-and-parquet', 'نوفر أفضل أنواع الأرضيات والباركيه والرخام والسيراميك، مع التركيب الاحترافي لضمان أعلى مستويات الجودة والمتانة.', NULL, 'services/6a39a703e46b1.webp', '["services\/gallery\/6a39a704af6ff.webp","services\/gallery\/6a39a7057ea0c.webp","services\/gallery\/6a39a70653499.webp"]', NULL, '4', '1', 'خدمة الأرضيات والباركيه في السعودية | تركيب باركيه وبورسلان وأرضيات فاخرة', 'نقدم خدمة الأرضيات والباركيه في السعودية بأحدث التصاميم العصرية، تشمل تركيب الباركيه، البورسلان، السيراميك، والأرضيات الفاخرة بأعلى جودة وتشطيبات احترافية تناسب المنازل والفلل.', 'الأرضيات والباركيه، تركيب باركيه، أرضيات خشبية، باركيه للمنازل، أرضيات مودرن، بورسلان أرضيات، سيراميك أرضيات، تصميم أرضيات داخلية، أرضيات فاخرة، ديكورات الأرضيات، أفضل أنواع الأرضيات، تركيب أرضيات حديثة، أرضيات فلل، أرضيات عصرية، تشطيب الأرضيات', '2026-06-19 02:14:24', '2026-06-22 21:20:07', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('6', 'الإضاءة والمرايا', 'lighting-and-mirrors', 'حلول إضاءة عصرية وديكورية مع مرايا فاخرة تعكس الأناقة وتخلق أجواء مثالية في كل مساحة.', NULL, 'services/mirror-svc-1.jpg', '["services\/gallery\/6a39a7ff6f6ce.webp","services\/gallery\/6a39a80029d08.webp","services\/gallery\/6a39a800ca25d.webp","services\/gallery\/6a39a80184e87.webp","services\/gallery\/6a39a8023cdff.webp","services\/gallery\/6a39a802eaa27.webp","services\/gallery\/6a39a803ac4e2.webp","services\/gallery\/6a39a80463b1a.webp"]', NULL, '5', '1', 'خدمة الإضاءة والمرايا في السعودية | تصميم إضاءة داخلية ومرايا ديكورية فاخرة', 'نقدم خدمة الإضاءة والمرايا في السعودية بتصاميم عصرية وفاخرة تشمل الإضاءة الداخلية والخارجية، والمرايا الديكورية للمجالس والصالات وغرف النوم لإضافة لمسة جمالية راقية للمساحات.', 'الإضاءة والمرايا، تصميم الإضاءة الداخلية، إضاءة مودرن، إضاءة المنازل، إضاءة ديكورية، إضاءة مخفية، إضاءة السقف، مرايا ديكورية، مرايا جدارية، ديكور مرايا، مرايا مودرن، إضاءة صالات، إضاءة غرف نوم، تنسيق الإضاءة المنزلية، تصميم إضاءة فاخرة', '2026-06-19 02:14:24', '2026-06-22 21:24:21', '1', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('8', 'الواجهات الخارجية', 'facades', 'تصميم وتنفيذ واجهات خارجية باستخدام الحجر والرخام والزجاج والعناصر المعمارية الحديثة لإطلالة مبهرة.', NULL, NULL, NULL, NULL, '6', '0', NULL, NULL, NULL, '2026-06-19 02:14:24', '2026-06-22 21:27:17', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('9', 'الحدائق والجلسات الخارجية', 'gardens-and-outdoor-sittings', 'تصميم حدائق وجلسات خارجية مريحة وجذابة، مع تنظيم المساحات الخضراء والممرات والإضاءة الخارجية.', NULL, 'services/6a39a93d3e1d7.webp', '["services\/gallery\/6a39a93e193f5.webp","services\/gallery\/6a39a93eda4f0.webp"]', NULL, '7', '1', 'خدمة تصميم الحدائق والجلسات الخارجية في السعودية | تنسيق حدائق وجلسات فاخرة', 'نقدم خدمة تصميم الحدائق والجلسات الخارجية في السعودية بأفكار عصرية تشمل تنسيق الحدائق، الجلسات الخارجية، المظلات، الإضاءة الخارجية، والشلالات لتجربة استرخاء فاخرة في منزلك.', 'الحدائق والجلسات الخارجية، تصميم حدائق منزلية، تنسيق حدائق، جلسات خارجية، جلسات حديقة، ديكور حدائق، تصميم جلسات خارجية، حدائق فلل، مظلات حدائق، إضاءة حدائق، جلسات خارجية فخمة، تنسيق الحدائق المنزلية، جلسات خارجية مودرن، شلالات حدائق، تصميم مساحات خارجية', '2026-06-19 02:14:24', '2026-06-22 21:29:35', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('11', 'التشطيبات', 'finishing', 'خدمات تشطيب متكاملة للمشاريع السكنية والتجارية، من البداية حتى التسليم النهائي بأعلى معايير الجودة.', NULL, 'services/6a39a9fcbeb89.webp', '["services\/gallery\/6a39a9fdc560c.webp","services\/gallery\/6a39a9fe86540.webp"]', NULL, '8', '1', 'خدمة التشطيبات في السعودية | تشطيب فلل ومنازل بأعلى جودة وتصميمات حديثة', 'نقدم خدمة التشطيبات في السعودية للمنازل والفلل بأعلى معايير الجودة، تشمل التشطيبات الداخلية والخارجية، الدهانات، الأرضيات، الأسقف، والديكورات الحديثة بتصاميم فاخرة ومتكاملة.', 'التشطيبات، تشطيب منازل، تشطيب فلل، التشطيبات الداخلية، التشطيبات الخارجية، أعمال التشطيب، تشطيبات حديثة، تشطيب كامل للمنزل، تشطيب فاخر، شركات التشطيب في السعودية، تشطيب عظم، تشطيب مفتاح، ديكورات وتشطيبات، أعمال الدهانات والتشطيب، خدمات التشطيب المنزلية', '2026-06-19 02:14:24', '2026-06-22 21:32:47', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('12', 'الصيانة والتجديد', 'maintenance-and-renovation', 'خدمات صيانة وتجديد شاملة للمنازل والمكاتب، تشمل إصلاح وتحديث الديكورات والبنية التحتية.', NULL, 'services/6a39aa8847089.webp', '["services\/gallery\/6a39aa890b896.webp","services\/gallery\/6a39aa89e5c00.webp","services\/gallery\/6a39aa8aad2fa.webp"]', NULL, '9', '1', 'خدمة الصيانة والتجديد في السعودية | ترميم وتجديد المنازل والفلل باحترافية عالية', 'نقدم خدمة الصيانة والتجديد في السعودية للمنازل والفلل بأعلى جودة، تشمل ترميم الجدران، إصلاح التشطيبات، تجديد الدهانات، تحديث الديكورات، وصيانة شاملة لإعادة المنزل بحالة حديثة وفاخرة.', 'الصيانة والتجديد، صيانة المنازل، تجديد المنازل، ترميم المنازل، صيانة الفلل، تجديد الفلل، ترميم وتشطيب، إصلاح الديكورات، صيانة داخلية، صيانة خارجية، تحديث المنازل، تجديد الدهانات، إصلاح التشطيبات، إعادة تأهيل المنازل، خدمات الصيانة المنزلية', '2026-06-19 02:14:24', '2026-06-22 21:35:07', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('13', 'ديكور شاشات التلفاز', 'tv-screen-decoration', 'نقدم أفضل تصاميم ديكور شاشات التلفاز بلمسات عصرية تجمع بين الفخامة والأناقة. نستخدم أجود المواد مثل بديل الخشب، الجبس بورد، الإضاءات المخفية، والأحجار الطبيعية لإبراز شاشة التلفاز كقطعة فنية في منزلك.', 'tv', 'services/tv-decoration-1.jpg', '["services\/gallery\/6a39a8407857c.webp","services\/gallery\/6a39a84132c08.webp","services\/gallery\/6a39a841d560c.webp","services\/gallery\/6a39a8428d121.webp","services\/gallery\/6a39a84357404.webp"]', NULL, '5', '1', 'ديكور شاشات التلفاز في السعودية | تصميم جدران التلفزيون مودرن وفاخرة', 'نقدم خدمة ديكور شاشات التلفاز في السعودية بتصاميم عصرية وفاخرة تشمل جدران التلفزيون بديل الرخام والخشب والجبس بورد مع إضاءة مخفية تناسب جميع أنماط الديكور الحديث.', 'ديكور شاشات التلفاز، ديكور تلفزيون مودرن، جدار التلفزيون، ديكور شاشة التلفزيون، بديل الرخام للتلفزيون، ديكور خشب للتلفزيون، جدار TV، ديكورات شاشات LED، تصميم جدار تلفزيون، ديكور جدران التلفاز، أفكار ديكور التلفزيون، ديكور صالة تلفزيون، جدار تلفاز جبس بورد، ديكور تلفزيون فخم، تصميم شاشة التلفاز مودرن', '2026-06-19 14:46:16', '2026-06-22 21:25:24', '0', NULL, '1');
INSERT INTO `services` (`id`, `name`, `slug`, `description`, `icon`, `image`, `images`, `videos`, `sort_order`, `is_active`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`, `views`, `canonical_url`, `is_indexed`) VALUES ('24', 'الدهانات والألوان', 'paints-and-colors', 'تشكيلة واسعة من الدهانات والألوان عالية الجودة للديكورات الداخلية والخارجية، تشمل الدهانات المائية والزيتية والعازلة والديكورية وجميع أنواع طلاء الأخشاب والمعادن', 'fa-paint-roller', 'services/6a39ab0cefce9.webp', '["services\/gallery\/6a39ab0dac528.webp","services\/gallery\/6a39ab0e72360.webp","services\/gallery\/6a39ab0f37da8.webp","services\/gallery\/6a39ab1006690.webp","services\/gallery\/6a39ab10e059c.webp","services\/gallery\/6a39ab1191baf.webp","services\/gallery\/6a39ab124877f.webp","services\/gallery\/6a39ab13011d7.webp","services\/gallery\/6a39ab13bbf9b.webp","services\/gallery\/6a39ab1478fbe.webp","services\/gallery\/6a39ab1538cd9.webp","services\/gallery\/6a39ab15e6055.webp","services\/gallery\/6a39ab169960f.webp","services\/gallery\/6a39ab174bbcc.webp","services\/gallery\/6a39ab18059fa.webp","services\/gallery\/6a39ab18be8fe.webp"]', NULL, '11', '1', 'خدمة الدهانات والألوان في السعودية | دهانات داخلية وخارجية بأحدث التصاميم', 'نقدم خدمة الدهانات والألوان في السعودية بأحدث التقنيات والتصاميم العصرية، تشمل الدهانات الداخلية والخارجية، اختيار الألوان المناسبة، والدهانات الديكورية لتناسب جميع أنماط الديكور الحديث.', 'الدهانات والألوان، دهانات داخلية، دهانات خارجية، ألوان الدهانات، دهانات جدران، دهانات حديثة، دهانات ديكورية، دهانات منازل، اختيار ألوان الدهان، دهانات فلل، دهانات مودرن، ألوان ديكور، تشطيب دهانات، أفضل ألوان الجدران، دهانات مقاومة للرطوبة', '2026-06-20 19:37:44', '2026-06-22 21:37:29', '0', NULL, '1');

DROP TABLE IF EXISTS `sessions`;
